section.content:
// Assessment Record (Dexie storage)
interface Assessment {
  id: string;                    // UUID
  timestamp: string;             // ISO 8601
  status: 'in_progress' | 'completed' | 'abandoned';
  questions: QuestionResult[];   // All 10 question results
  domainScores: DomainScores;    // Aggregated by category
  trainingPlanWeights: TrainingWeights;
  totalDuration: number;         // milliseconds
  confidenceRatings: ConfidenceRatings;
}

// Individual Question Result
interface QuestionResult {
  questionId: string;
  domain: 'number_sense' | 'spatial' | 'operations';
  questionType: string;          // e.g., 'quantity_comparison', 'number_line'
  correct: boolean;
  responseTime: number;          // milliseconds
  userAnswer: string | number;
  expectedAnswer: string | number;
  difficulty: 1 | 2 | 3;         // Easy, Medium, Hard
  confidenceBefore?: number;     // 1-5 scale (optional per-question)
}

// Domain Score Aggregation
interface DomainScores {
  number_sense: {
    score: number;               // 0-100
    questionsCorrect: number;
    totalQuestions: number;
    averageResponseTime: number;
    isWeakness: boolean;         // score < 60
  };
  spatial: { /* same structure */ };
  operations: { /* same structure */ };
}

// Training Plan Weights
interface TrainingWeights {
  number_sense: number;          // 0.5 (strength) to 2.0 (weakness)
  spatial: number;
  operations: number;
  generatedAt: string;           // ISO 8601
}

// ScoringService
interface ScoringService {
  calculateDomainScore(results: QuestionResult[], domain: string): DomainScore;
  identifyWeaknesses(domainScores: DomainScores): string[];
  generateTrainingWeights(domainScores: DomainScores): TrainingWeights;
}

artifact.content:
export interface Assessment {
  id?: number;
  timestamp: string;
  status: "in-progress" | "completed";
  totalQuestions: number;
  correctAnswers: number;
  weaknesses: string[];     // e.g., ["number-sense", "spatial-rotation"]
  strengths: string[];
  recommendations: string[];
  userId: string;          // Always "local_user"
}

import Dexie, { type Table } from 'dexie';
import type { Assessment } from './schemas';

export class DiscalculasDB extends Dexie {
  assessments!: Table<Assessment, number>;

  constructor() {
    super('DiscalculasDB');
    this.version(1).stores({
      assessments: '++id, timestamp, status',
      // ... other tables
    });
  }
}

export const db = new DiscalculasDB();

// Example usage:
// await db.assessments.add({ timestamp: new Date().toISOString(), ... });
// const latest = await db.assessments.orderBy('timestamp').reverse().first();

// Example question config with domain field
export interface QuestionConfig {
  id: string;
  domain: 'number_sense' | 'spatial' | 'operations';
  type: string;
  difficulty: 1 | 2 | 3;
  // ... other fields
}

// Questions 1-4: Number Sense
// Questions 5-7: Spatial
// Questions 8-10: Operations

export interface BasicOperationsResult {
  userAnswer: number;
  isCorrect: boolean;
  timeToAnswer: number;
  operationType: string;
  correctAnswer: number;
}

// Each question type returns a result with:
// - userAnswer
// - isCorrect (boolean)
// - timeToAnswer (milliseconds via performance.now())
// - domain-specific metadata

interface.signature:
function calculateDomainScore(
  questions: Array<{ domain: string; isCorrect: boolean }>,
  domain: 'number_sense' | 'spatial' | 'operations'
): number

function identifyWeaknesses(
  domainScores: Record<string, number>
): { weaknesses: string[]; moderate: string[]; strengths: string[] }

function generateWeights(
  categories: { weaknesses: string[]; moderate: string[]; strengths: string[] }
): Record<string, number>

interface.description:
// Retrieve latest assessment
const latest = await db.assessments.orderBy('timestamp').reverse().first();

// Update assessment with scores
await db.assessments.update(id, {
  status: 'completed',
  weaknesses: ['number_sense'],
  strengths: ['spatial', 'operations'],
  // ... other fields
});

// Add new assessment
const id = await db.assessments.add({
  timestamp: new Date().toISOString(),
  status: 'in-progress',
  totalQuestions: 10,
  correctAnswers: 0,
  weaknesses: [],
  strengths: [],
  recommendations: [],
  userId: 'local_user'
});
